// And groups predicates with the AND operator between them.
func And(predicates ...predicate.SubReport) predicate.SubReport {
	return predicate.SubReport(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.SubReport) predicate.SubReport {
	return predicate.SubReport(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.SubReport) predicate.SubReport {
	return predicate.SubReport(sql.NotPredicates(p))
}
